-- ── NotebookLM ───────────────────────────────────────────────
UPDATE public.ai_tools SET
  features = '{"en":["Upload PDFs, docs, slides and websites as sources","AI answers grounded strictly in your uploaded documents","Auto-generate study guides and summaries","Audio Overview: podcast-style conversation on your docs","Cite sources inline with every answer","Supports multiple documents simultaneously","Free to use with Google account"],"hi":["PDF, दस्तावेज़, स्लाइड और वेबसाइट अपलोड करें","AI जवाब सिर्फ आपके अपलोड किए दस्तावेज़ों पर आधारित","स्वचालित अध्ययन गाइड और सारांश बनाएं","Audio Overview: आपके दस्तावेज़ों पर पॉडकास्ट-स्टाइल बातचीत","हर जवाब में इनलाइन सोर्स उद्धरण","एक साथ कई दस्तावेज़ समर्थन","Google अकाउंट से मुफ्त उपयोग"],"hinglish":["PDF, docs, slides aur websites upload karo","AI answers sirf aapke uploaded documents pe based","Auto study guides aur summaries banao","Audio Overview: aapke docs pe podcast-style conversation","Har answer mein inline source citations","Multiple documents simultaneously support","Google account se free use"]}',
  pros = '{"en":["Answers are 100% grounded in your documents — no hallucination","Audio Overview feature is uniquely useful for learning","Completely free with Google account","Great for students and researchers","Handles large documents well"],"hi":["जवाब 100% आपके दस्तावेज़ों पर आधारित — कोई हैल्युसिनेशन नहीं","Audio Overview फीचर सीखने के लिए अनोखा उपयोगी","Google अकाउंट से बिल्कुल मुफ्त","छात्रों और शोधकर्ताओं के लिए बेहतरीन","बड़े दस्तावेज़ों को अच्छे से संभालता है"],"hinglish":["Answers 100% aapke documents pe based — no hallucination","Audio Overview feature seekhne ke liye uniquely useful","Google account se bilkul free","Students aur researchers ke liye great","Large documents achhe se handle karta hai"]}',
  cons = '{"en":["Cannot answer questions outside uploaded sources","No real-time web search","Limited to Google ecosystem","Hindi document analysis can be inconsistent"],"hi":["अपलोड किए सोर्स के बाहर के सवालों का जवाब नहीं दे सकता","रियल-टाइम वेब सर्च नहीं","Google इकोसिस्टम तक सीमित","हिंदी दस्तावेज़ विश्लेषण कभी-कभी असंगत"],"hinglish":["Uploaded sources ke bahar ke sawaalon ka jawab nahi de sakta","Real-time web search nahi","Google ecosystem tak limited","Hindi document analysis kabhi kabhi inconsistent"]}',
  use_cases = '{"en":["Studying textbooks and research papers","Legal document analysis","Preparing for exams from lecture slides","Summarizing annual reports and business documents","Creating study notes from multiple sources","Podcast-style revision of any topic"],"hi":["पाठ्यपुस्तकें और शोध पत्र पढ़ना","कानूनी दस्तावेज़ विश्लेषण","लेक्चर स्लाइड से परीक्षा की तैयारी","वार्षिक रिपोर्ट और व्यापार दस्तावेज़ सारांश","कई सोर्स से अध्ययन नोट्स बनाना","किसी भी विषय का पॉडकास्ट-स्टाइल रिवीजन"],"hinglish":["Textbooks aur research papers padhna","Legal document analysis","Lecture slides se exam ki taiyaari","Annual reports aur business documents summarize karna","Multiple sources se study notes banana","Kisi bhi topic ka podcast-style revision"]}',
  alternatives = ARRAY['perplexity-ai','claude','chatgpt','elicit'],
  hindi_summary = 'NotebookLM Google का एक मुफ्त AI टूल है जो आपके अपने दस्तावेज़ों — PDF, नोट्स, स्लाइड — पर काम करता है। यह हैल्युसिनेशन नहीं करता क्योंकि यह सिर्फ आपके दिए गए सोर्स से जवाब देता है। Audio Overview फीचर से आप किसी भी दस्तावेज़ को पॉडकास्ट की तरह सुन सकते हैं।'
WHERE slug = 'notebooklm';

