  cons = '{"en":["Requires X Premium subscription for full access","Less accurate than GPT-4 for technical tasks","Smaller ecosystem than ChatGPT","Can be too casual for professional use"],"hi":["पूर्ण पहुंच के लिए X Premium सब्सक्रिप्शन जरूरी","तकनीकी कार्यों के लिए GPT-4 से कम सटीक","ChatGPT से छोटा इकोसिस्टम","पेशेवर उपयोग के लिए बहुत आरामदायक हो सकता है"],"hinglish":["Full access ke liye X Premium subscription zaroori","Technical tasks ke liye GPT-4 se kam accurate","ChatGPT se chhota ecosystem","Professional use ke liye bahut casual ho sakta hai"]}',
  use_cases = '{"en":["Tracking real-time social media trends","Research on current news and viral topics","Fun and casual AI conversations","Image generation for social content","Market sentiment analysis from Twitter","Keeping up with tech and startup news"],"hi":["रियल-टाइम सोशल मीडिया ट्रेंड ट्रैक करना","करंट न्यूज़ और वायरल विषयों पर रिसर्च","मजेदार और आकस्मिक AI बातचीत","सोशल कंटेंट के लिए इमेज जनरेशन","Twitter से मार्केट सेंटिमेंट विश्लेषण","टेक और स्टार्टअप खबरों से अपडेट रहना"],"hinglish":["Real-time social media trends track karna","Current news aur viral topics pe research","Fun aur casual AI conversations","Social content ke liye image generation","Twitter se market sentiment analysis","Tech aur startup news ke saath updated rehna"]}',
